#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long N, K; scanf("%lld %lld", &N, &K);
        long long d = N / K;
        for(long long i=1;i<=K;i++){
            printf("%lld", i*d);
            if(i<K) printf(" ");
        }
        if(T) printf("\n");
    }
    return 0;
}

